//Receipt voucher currency and background Bank charges curreny in receipt should be the same
// Validate currency before modification or posting
private void validateCurrency()
{
    LedgerJournalTrans ledgerJournalTrans;
    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::No)
    {
        return;
    }
    select firstonly RecId from ledgerJournalTrans
        where ledgerJournalTrans.RecId == this.RefRecId
        && ledgerJournalTrans.CurrencyCode != this.FeeCurrency;

    if (ledgerJournalTrans.RecId)
    {
        DialogButton response = Box::yesNo("@ETG_New:CurrencyMismatched1", DialogButton::No);

        if (response == DialogButton::No)
        {
            throw Error("@ETG_New:TransactionCanceled");
        }
    }
}

public boolean validateField(fieldId _fieldIdToCheck)
{
    boolean isValid = next validateField(_fieldIdToCheck);

    if (isValid)
    {
        switch (_fieldIdToCheck)
        {
            case fieldNum(CustVendPaymJournalFee, FeeCurrency):
                if (this.FeeCurrency)
                {
                    this.validateCurrency();
                }
                break;
        }
    }

    return isValid;
}

// Validation on posting
public boolean validateWrite()
{
    boolean isValid = next validateWrite(); 

    if(isValid)
    {
        this.validateCurrency();
    }

    return isValid;
}
